{
  "activities": [
    {
      "type": "activity",
      "title": "Reading Comprehension through Unseen Passage",
      "unit_name": "Reading Skills",
      "chapter_name": "Reading Skills",
      "details": "Students engage in reading discursive passages (400-450 words) and case-based factual passages with visual input (200-250 words). Activities include answering Multiple Choice Questions, Objective Type Questions, and Very Short Answer Questions to assess comprehension, interpretation, analysis, inference, evaluation, and vocabulary."
    },
    {
      "type": "activity",
      "title": "Grammar Accuracy Exercises",
      "unit_name": "Writing Skills and Grammar",
      "chapter_name": "Writing Skills and Grammar",
      "details": "Students practice Determiners, Tenses, Modals, Subject-verb concord, and Reported speech through Gap Filling, Editing, and Transformation exercises. Focus is on accurate use of spelling, punctuation, and grammar."
    },
    {
      "type": "activity",
      "title": "Descriptive Paragraph Writing",
      "unit_name": "Writing Skills and Grammar",
      "chapter_name": "Writing Skills and Grammar",
      "details": "Students write descriptive paragraphs (100-120 words) describing a person, event, or situation based on visual or verbal cues."
    },
    {
      "type": "activity",
      "title": "Story Writing and Diary Entry",
      "unit_name": "Writing Skills and Grammar",
      "chapter_name": "Writing Skills and Grammar",
      "details": "Students write a story on a given cue/title or a diary entry (100-120 words) to demonstrate creative expression."
    },
    {
      "type": "activity",
      "title": "Reference to the Context Analysis",
      "unit_name": "Language through Literature",
      "chapter_name": "Reference to the Context",
      "details": "Students analyze extracts from Drama/Prose and Poetry, answering Multiple Choice Questions to assess interpretation, analysis, inference, evaluation, appreciation, and vocabulary."
    },
    {
      "type": "activity",
      "title": "Short Answer Questions Discussion",
      "unit_name": "Language through Literature",
      "chapter_name": "Short & Long Answer Questions",
      "details": "Students answer short answer questions (40-50 words) from Beehive and Moments to assess interpretation, analysis, inference, and evaluation."
    },
    {
      "type": "activity",
      "title": "Long Answer Type Creative Writing",
      "unit_name": "Language through Literature",
      "chapter_name": "Short & Long Answer Questions",
      "details": "Students answer long answer questions (100-120 words) from Beehive and Moments, focusing on creativity, imagination, extrapolation beyond the text, theme interpretation, or character sketches."
    },
    {
      "type": "activity",
      "title": "Role Play and Skit Performance",
      "unit_name": "Language through Literature",
      "chapter_name": "Short & Long Answer Questions",
      "details": "Students participate in role plays, skits, and dramatizations based on texts from Beehive and Moments to enhance listening and speaking skills."
    },
    {
      "type": "activity",
      "title": "Group Discussion and Peer Interaction",
      "unit_name": "Language through Literature",
      "chapter_name": "Short & Long Answer Questions",
      "details": "Students engage in classroom interactions, group work, and discussions to express ideas, defend views, and participate actively."
    }
  ],
  "projects": [
    {
      "title": "Art-Integrated Project: Role Play/Skit/Dramatization",
      "unit_name": "Language through Literature",
      "chapter_name": "Short & Long Answer Questions",
      "details": "Students create and perform art-integrated projects based on activities like role play, skit, or dramatization derived from the prescribed texts (Beehive/Moments) to assess listening and speaking skills."
    }
  ],
  "practicals": [
    {
      "title": "Listening and Speaking Skills Assessment",
      "unit_name": "Language through Literature",
      "chapter_name": "Short & Long Answer Questions",
      "details": "Regular practice and assessment of listening and speaking skills (05 marks) involving oral activities, discussions, and presentations based on the curriculum texts."
    }
  ]
}
